static bool bool_try_cast_i64(py_Ref arg, py_i64* out) {
    if (arg->type == tp_int) {
        *out = py_toint(arg);
        return true;
    } else if (arg->type == tp_bool) {
        *out = py_tobool(arg);
        return true;
    } else {
        return false;
    }
}

